import{_ as e,c as a,a as s,o as n}from"./app-CEcM0piI.js";const i={};function d(l,t){return n(),a("div",null,t[0]||(t[0]=[s(`<p>反射允许对封装类的字段，方法和构造函数的信息进行编程访问 反射就是：加载类，并允许以编程的方式解剖类中的各种成分（成员变量、方法、构造器等）。</p><table><thead><tr><th>工具类</th><th>作用</th></tr></thead><tbody><tr><td>Class</td><td>获取class对象</td></tr><tr><td>Constructor</td><td>获取构造方法</td></tr><tr><td>Field</td><td>获取成员变量</td></tr><tr><td>Method</td><td>获取成员方法</td></tr></tbody></table><h3 id="获取class对象" tabindex="-1"><a class="header-anchor" href="#获取class对象"><span>获取class对象</span></a></h3><p>三种方法:</p><ul><li>Class.forName(&quot;全类名&quot;); 编码阶段使用</li><li>类名.class 加载阶段(将字节码文件加载到内存中),一般当作参数进行传递</li><li>对象.getClass(); 运行阶段,当有这个类的对象时才使用</li></ul><p>全类名:包名+类名</p><h3 id="获取构造方法constructor" tabindex="-1"><a class="header-anchor" href="#获取构造方法constructor"><span>获取构造方法Constructor</span></a></h3><p>Class的成员函数</p><table><thead><tr><th>成员函数</th><th>作用</th></tr></thead><tbody><tr><td>Constructor&lt;?&gt;[]getConstructors)</td><td>返回所有公共构造方法对象的数组</td></tr><tr><td>Constructor&lt;?&gt;[]getDeclaredConstructors()</td><td>返回所有构造方法对象的数组</td></tr><tr><td>Constructor&lt;T&gt; getConstructor(Class&lt;?&gt;.parameterTypes)</td><td>返回单个公共构造方法对象</td></tr><tr><td>Constructor&lt;T&gt; getDeclaredConstructor(Class&lt;?&gt;...parameterTypes)</td><td>返回单个构造方法对象</td></tr><tr><td>T newlnstance(Object...initargs)</td><td>根据指定的构造方法创建对象</td></tr><tr><td>setAccessible(boolean flag)</td><td>设置为true,表示取消访问检查</td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Class clazz=Class.forName(&quot;com.itheima.Student&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Constructor con3=clazz.getonstructor(int.class);</span></span>
<span class="line"><span>System.out.println(con3);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>获取指定参数的构造方法传入的也要是该类型的字节码文件</p><h4 id="获取形参列表" tabindex="-1"><a class="header-anchor" href="#获取形参列表"><span>获取形参列表</span></a></h4><p>Constructor的成员函数</p><table><thead><tr><th>成员函数</th><th>说明</th></tr></thead><tbody><tr><td>Parameter[] getParameters();</td><td>获取构造函数的形参列表</td></tr><tr><td>&lt;T&gt; newInstance(T ...initargs)</td><td>传入获取到的构造函数新建一个对象,但无法使用私有构造</td></tr><tr><td>void setAccessible(boolean flag)</td><td>临时取消权限校验</td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>con4.setAccessible(true);//con4是一个私有的构造函数,需要取消权限校验才能调用</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Student stu =(Student)con4.newInstance(..initargs:&quot;张三&quot;,23);</span></span>
<span class="line"><span>System.out.println(stu);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="利用反射获取成员变量" tabindex="-1"><a class="header-anchor" href="#利用反射获取成员变量"><span>利用反射获取成员变量</span></a></h3><p>Class中的方法</p><table><thead><tr><th>成员函数</th><th>说明</th></tr></thead><tbody><tr><td>Field[] getFields()</td><td>返回所有公共成员变量对象的数组</td></tr><tr><td>Field[] getDeclaredFields()</td><td>返回所有成员变量对象的数组</td></tr><tr><td>Field getField(String name)</td><td>返回单个公共成员变量对象根据成员变量名获取</td></tr><tr><td>Field getDeclaredField(String name)</td><td>返回单个成员变量对象根据成员变量名获取</td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Fieldggender =clazz.getField()&quot;gender&quot;);</span></span>
<span class="line"><span>System.out.println(gender);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>Field类中用于创建对象的方法</p><table><thead><tr><th>成员函数</th><th>说明</th></tr></thead><tbody><tr><td>void set(Object obj, Object value)</td><td>赋值</td></tr><tr><td>Object get(Object obj)</td><td>获取值</td></tr><tr><td>int getModifiers()</td><td>获取权限修饰符</td></tr><tr><td>String getName()</td><td>获取成员变量名</td></tr><tr><td>Class&lt;?&gt; getType()</td><td>获取成员变量类型</td></tr></tbody></table><h3 id="获取成员方法" tabindex="-1"><a class="header-anchor" href="#获取成员方法"><span>获取成员方法</span></a></h3><p>Class类中的</p><table><thead><tr><th>成员函数</th><th>说明</th></tr></thead><tbody><tr><td>Method[] getMethods()</td><td>返回所有公共成员方法对象的数组，包括继承的</td></tr><tr><td>Method[] getDeclaredMethods()</td><td>返回所有成员方法对象的数组，不包括继承的</td></tr><tr><td>Method getMethod(String name, Class&lt;?&gt;.. parameterTypes）</td><td>返回单个公共成员方法对象</td></tr><tr><td>Method getDeclaredMethod(String name, Class&lt;?&gt;...parameterTypes)</td><td>返回单个成员方法对象</td></tr></tbody></table><p>Method类中用于创建对象的方法</p><table><thead><tr><th>成员函数</th><th>说明</th></tr></thead><tbody><tr><td>Objectinvoke(Objeectobj,Object... args)</td><td>运行方法.参数一：用obj对象调用该方法<br>参数二：调用方法的传递的参数（如果没有就不写）<br>返回值：方法的返回值(如果没有就不写)</td></tr><tr><td>Class[] getExceptionTypes()</td><td>获取抛出的异常</td></tr></tbody></table><table><thead><tr><th>成员函数</th><th>说明</th></tr></thead><tbody><tr><td>String value()</td><td>获取注解的值</td></tr></tbody></table><p>使用同样的函数也能获得方法的修饰符,形参,名字等</p><h3 id="获取注解" tabindex="-1"><a class="header-anchor" href="#获取注解"><span>获取注解</span></a></h3><table><thead><tr><th>成员函数</th><th>说明</th></tr></thead><tbody><tr><td>Annotation[] getAnnotations()</td><td>获取所有注解</td></tr><tr><td>Annotation getAnnotation(Class class)</td><td>获取单个注解</td></tr><tr><td>Field getDeclaredField(String name)</td><td>根据名字获取指定名字成员的注解</td></tr></tbody></table><table><thead><tr><th>成员函数</th><th>说明</th></tr></thead><tbody><tr><td>String value()</td><td>获取注解的值</td></tr></tbody></table><h1 id="注解" tabindex="-1"><a class="header-anchor" href="#注解"><span>注解</span></a></h1><p>从Java5开始，Java 增加了对注解（Annotation）的支持，它是代码中的一种特殊标记，可以在编译、类加载和运行时被读取，执行相应的处理。开发人员可以通过注解在不改变原有代码和逻辑的情况下，在源代码中嵌入补充信息</p><h2 id="内置注解" tabindex="-1"><a class="header-anchor" href="#内置注解"><span>内置注解</span></a></h2><ul><li><p>@Override：定义在java.lang.c1.Override中，此注释只适用于修辞方法，表示一个方法声明打算 重写超类中的另一个方法声明</p></li><li><p>@Deprecated：定义在java.lang.Deprecated中，此注释可以用于修辞方法，属性，类，表示不 鼓励程序员使用这样的元素，通常是因为它很危险或者存在更好的选择</p></li><li><p>@SuppressWarnings：定义在java.lang.SuppressWarnings中,用来抑制编译时的警告信息 与前两个注释有所不同，你需要添加一个参数才能正确使用，这些参数都是已经定义好了的， 我们选择性的使用就好了， @SuppressWarnings(&quot;all&quot;) @SuppressWarnings(&quot;unchecked&quot;) @SuppressWarnings(value={&quot;unchecked&quot;,&quot;deprecation&quot;})等</p></li></ul><h2 id="元注解" tabindex="-1"><a class="header-anchor" href="#元注解"><span>元注解</span></a></h2><p>元注解的作用就是负责注解其他注解，Java定义了4个标准的meta-annotation类型,他们被用来 提供对其他annotation类型作说明</p><p>类型和它们所支持的类在java.lang.annotation包中可以找到:</p><ul><li>@Target : 用于描述注解的使用范围(即：被描述的注解可以用在什么地方) 使用value参数指出可使用的类型</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@target(value=ElementType.METHOD)</span></span>
<span class="line"><span>@interface MyAnnotation{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>多个类型都可使用该注解需要将类型用大括号列出来</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@Target(value ={ElementType.METHOD, ElementType.TYPE})</span></span>
<span class="line"><span>@interfaceMyAnnotation{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>@Retention : 表示需要在什么级别保存该注释信息，用于描述注解的生命周期 表示该注解在什么时期还有效 value参数用来指出生命周期 SOURCE : 源码时期 CLASS : 字节码时期 RUNTIME : 运行时</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@Target(value={ElementType.METHoD,ElementType.TYPE})</span></span>
<span class="line"><span>@Retention(value=RetentionPolicy.RUNTIME)</span></span>
<span class="line"><span>@interface MyAnnotation{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>@Documented : 说明该注解将被包含在javadoc中</li><li>@lnherited : 说明子类可以继承父类中的该注解</li></ul><h2 id="自定义注解" tabindex="-1"><a class="header-anchor" href="#自定义注解"><span>自定义注解</span></a></h2><p>使用@interface自定义注解不加@只能是接口</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@interface MyAnnotation{</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在注解中添加成员变量需要在成员变量名后添加小括号 在使用注解时没有默认值的成员变量必须要传参 可以使用defalut设置默认值,使用大括号传入数组</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@interface MyAnnotation{</span></span>
<span class="line"><span>	String name()default&quot;&quot;;</span></span>
<span class="line"><span>	int age();</span></span>
<span class="line"><span>	String[] schools();</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@MyAnnotation(age=10,schools={&quot;a&quot;,&quot;b&quot;})</span></span>
<span class="line"><span>public void test(){</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,50)]))}const h=e(i,[["render",d]]),p=JSON.parse('{"path":"/back/java/8/","title":"8 反射和注解","lang":"zh-CN","frontmatter":{"title":"8 反射和注解","createTime":"2025/04/05 12:12:26","permalink":"/back/java/8/"},"readingTime":{"minutes":4.98,"words":1495},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/Java/8 反射和注解.md","headers":[]}');export{h as comp,p as data};
